exercises.solution_code:
#include <iostream>

void classify(int& x)
{
    std::cout << "l-value: " << x << '\n';
}

void classify(int&& x)
{
    std::cout << "r-value: " << x << '\n';
}

int main()
{
    int n{};
    std::cin >> n;

    classify(n);
    classify(42);
    classify(n + 1);

    return 0;
}

