exercises.solution_code:
#include <iostream>

int main()
{
    int a{};
    int b{};
    std::cin >> a >> b;

    int&& ref{a + b};

    std::cout << "sum: " << ref << '\n';
    std::cout << "doubled: " << ref * 2 << '\n';
    std::cout << "offset: " << ref + 100 << '\n';

    return 0;
}
